import _ from 'lodash';
import moment from 'moment';

const casters = {
  // string: (data: string | null) => data,
  date: (data: string | null) => (data ? moment(data).toDate() : null),
};

export type CastableTypes = keyof typeof casters;

export abstract class BaseModel {
  protected static _cast: Record<string, CastableTypes> = {};

  init(klass: typeof BaseModel, data?: any) {
    this.mapToSelf(this.castValues(klass, data));
  }
  /**
   * Maps kv of `data` to this instance.
   * This method has side effect.
   * @param data
   */
  mapToSelf(data?: any) {
    for (const k in data) {
      const v = _.get(data, k);
      _.set(this, k, v);
    }
  }

  /**
   * Casts values defined in <T>._cast .
   * This method has side effect to `obj`.
   */
  castValues(klass: typeof BaseModel, data?: any) {
    if (!data) {
      return data;
    }
    for (const k in data) {
      const v = _.get(data, k);
      const typeNameCastedInto: CastableTypes | null = _.get(
        klass._cast,
        k,
        null,
      );
      const caster = typeNameCastedInto ? casters[typeNameCastedInto] : null;
      if (caster) {
        _.set(data, k, caster(v));
      }
    }
    return data;
  }

  static newInstances<T extends BaseModel>(
    type: { new (data: Partial<{ [Property in keyof T]: T[Property] }>): T },
    data?: Partial<{ [Property in keyof T]: T[Property] }>[] | null,
  ): T[] {
    return (data
      ?.map((x) => this.newInstance(type, x))
      .filter((x) => !_.isNil(x)) ?? []) as T[];
  }

  /**
   * Builds an instance of `type` from `data`.
   * This method returns null if the `data` is empty.
   * This calls constructor of `type` so that it can make nested properties of BaseModel recursively.
   * @param type
   * @param data
   * @returns
   */
  static newInstance<T extends BaseModel>(
    type: { new (data: Partial<{ [_Property in keyof T]: T[any] }>): T },
    data?: Partial<{ [_Property in keyof T]: T[any] } | null>,
  ): T | null {
    if (_.isNil(data)) {
      return null;
    }
    return new type(data);
  }
}

